contracts/ZaaNetAdminV1.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

import "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/utils/PausableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "./utils/ReentrancyGuardUpgradeable.sol";
import "./ZaaNetStorageV1.sol";

/**
 * @title ZaaNetAdminV1
 * @dev Upgradeable admin contract for ZaaNet platform - Version 1
 * @notice Manages fees, treasury, and administrative functions
 */
contract ZaaNetAdminV1 is
    OwnableUpgradeable,
    PausableUpgradeable,
    UUPSUpgradeable,
    ReentrancyGuardUpgradeable
{
    // Maximum fees
    uint256 public constant MAX_PLATFORM_FEE = 20; // 20% maximum
    uint256 public constant MAX_HOSTING_FEE = 100 * (10 ** 6); // 100 USDT max
    uint256 public constant MAX_HOST_VOUCHER_FEE = 100 * (10 ** 6); // 100 USDT max per tier

    ZaaNetStorageV1 public storageContract;
    address public treasuryAddress; // Address to receive platform fees
    address public paymentAddress; // Address to make voucher payments
    uint256 public platformFeePercent; // Platform fee percentage (1-20%)
    uint256 public hostingFee; // Hosting fee in USDT (6 decimals)

    // Host voucher registration fee per voucher (USDT 6 decimals): tier 0 = hours (≤24h), tier 1 = days (≤30d), tier 2 = months (>30d)
    uint256 public hostVoucherFeeHours;
    uint256 public hostVoucherFeeDays;
    uint256 public hostVoucherFeeMonths;

    // Emergency controls
    bool public emergencyMode;
    mapping(address => bool) public emergencyOperators;

    // Time lock for emergency toggles - prevents rapid toggling
    uint256 public constant EMERGENCY_COOLDOWN = 1 hours;
    uint256 public lastEmergencyToggleTime;
    mapping(address => uint256) public lastEmergencyToggleBy;

    // Fee history for transparency
    struct FeeChange {
        uint256 oldFee;
        uint256 newFee;
        uint256 timestamp;
        address changedBy;
    }

    FeeChange[] public feeHistory;

    // Treasury change history
    struct TreasuryChange {
        address oldTreasury;
        address newTreasury;
        uint256 timestamp;
        address changedBy;
    }

    TreasuryChange[] public treasuryHistory;

    // Hosting fee history
    struct HostingFeeChange {
        uint256 oldFee;
        uint256 newFee;
        uint256 timestamp;
        address changedBy;
    }

    HostingFeeChange[] public hostingFeeHistory;

    // Events
    event PlatformFeeUpdated(
        uint256 indexed oldFee,
        uint256 indexed newFee,
        address indexed changedBy
    );
    event TreasuryUpdated(
        address indexed oldTreasury,
        address indexed newTreasury,
        address indexed changedBy
    );
    event HostingFeeUpdated(
        uint256 indexed oldFee,
        uint256 indexed newFee,
        address indexed changedBy
    );
    event HostVoucherFeeTierUpdated(
        uint8 indexed tier,
        uint256 indexed newFee,
        address indexed changedBy
    );
    event PaymentAddressUpdated(
        address indexed oldAddress,
        address indexed newAddress,
        address indexed changedBy
    );
    event AdminPaused(address indexed triggeredBy);
    event AdminUnpaused(address indexed triggeredBy);
    event EmergencyModeToggled(bool enabled, address indexed triggeredBy);
    event EmergencyOperatorUpdated(
        address indexed operator,
        bool status,
        address indexed updatedBy
    );
    event ContractsInitialized(
        address indexed storageContract,
        uint256 timestamp
    );

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {}

    /// @dev Required by UUPSUpgradeable
    function _authorizeUpgrade(address) internal override onlyOwner {}

    function initialize(
        address _storageContract,
        address _treasuryAddress,
        address _paymentAddress,
        uint256 _platformFeePercent,
        uint256 _hostingFee
    ) public initializer {
        __Ownable_init(msg.sender);
        __Pausable_init();
        __ReentrancyGuard_init();

        // Initialize state variables
        emergencyMode = false;
        lastEmergencyToggleTime = 0;

        require(
            _treasuryAddress != address(0),
            "Treasury cannot be zero address"
        );
        require(
            _platformFeePercent <= MAX_PLATFORM_FEE,
            "Platform fee exceeds maximum"
        );
        require(
            _paymentAddress != address(0),
            "Payment address cannot be zero address"
        );
        require(_hostingFee <= MAX_HOSTING_FEE, "Hosting fee exceeds maximum");

        if (_storageContract != address(0)) {
            storageContract = ZaaNetStorageV1(_storageContract);
            emit ContractsInitialized(_storageContract, block.timestamp);
        }

        treasuryAddress = _treasuryAddress;
        paymentAddress = _paymentAddress;
        platformFeePercent = _platformFeePercent;
        hostingFee = _hostingFee;

        // Record initial settings
        feeHistory.push(
            FeeChange({
                oldFee: 0,
                newFee: _platformFeePercent,
                timestamp: block.timestamp,
                changedBy: msg.sender
            })
        );

        treasuryHistory.push(
            TreasuryChange({
                oldTreasury: address(0),
                newTreasury: _treasuryAddress,
                timestamp: block.timestamp,
                changedBy: msg.sender
            })
        );

        hostingFeeHistory.push(
            HostingFeeChange({
                oldFee: 0,
                newFee: _hostingFee,
                timestamp: block.timestamp,
                changedBy: msg.sender
            })
        );

        // Set owner as emergency operator
        emergencyOperators[msg.sender] = true;
        emit EmergencyOperatorUpdated(msg.sender, true, msg.sender);
    }

    modifier onlyEmergencyOperator() {
        require(
            emergencyOperators[msg.sender] || msg.sender == owner(),
            "Not emergency operator"
        );
        _;
    }

    modifier notInEmergencyMode() {
        require(!emergencyMode, "System in emergency mode");
        _;
    }

    function setPlatformFee(
        uint256 _newFeePercent
    ) external onlyOwner notInEmergencyMode {
        require(_newFeePercent <= MAX_PLATFORM_FEE, "Fee exceeds maximum");
        require(_newFeePercent != platformFeePercent, "Fee unchanged");

        uint256 oldFee = platformFeePercent;
        platformFeePercent = _newFeePercent;

        // Record fee change
        feeHistory.push(
            FeeChange({
                oldFee: oldFee,
                newFee: _newFeePercent,
                timestamp: block.timestamp,
                changedBy: msg.sender
            })
        );

        emit PlatformFeeUpdated(oldFee, _newFeePercent, msg.sender);
    }

    function setHostingFee(
        uint256 _newFee
    ) external onlyOwner notInEmergencyMode {
        require(_newFee <= MAX_HOSTING_FEE, "Fee exceeds maximum");
        require(_newFee != hostingFee, "Fee unchanged");

        uint256 oldFee = hostingFee;
        hostingFee = _newFee;

        // Record hosting fee change
        hostingFeeHistory.push(
            HostingFeeChange({
                oldFee: oldFee,
                newFee: _newFee,
                timestamp: block.timestamp,
                changedBy: msg.sender
            })
        );

        emit HostingFeeUpdated(oldFee, _newFee, msg.sender);
    }

    /// @notice Set host voucher registration fee for hours tier (≤24h), USDT 6 decimals
    function setHostVoucherFeeHours(
        uint256 _fee
    ) external onlyOwner notInEmergencyMode {
        require(_fee <= MAX_HOST_VOUCHER_FEE, "Fee exceeds maximum");
        hostVoucherFeeHours = _fee;
        emit HostVoucherFeeTierUpdated(0, _fee, msg.sender);
    }

    /// @notice Set host voucher registration fee for days tier (≤30d), USDT 6 decimals
    function setHostVoucherFeeDays(
        uint256 _fee
    ) external onlyOwner notInEmergencyMode {
        require(_fee <= MAX_HOST_VOUCHER_FEE, "Fee exceeds maximum");
        hostVoucherFeeDays = _fee;
        emit HostVoucherFeeTierUpdated(1, _fee, msg.sender);
    }

    /// @notice Set host voucher registration fee for months tier (>30d), USDT 6 decimals
    function setHostVoucherFeeMonths(
        uint256 _fee
    ) external onlyOwner notInEmergencyMode {
        require(_fee <= MAX_HOST_VOUCHER_FEE, "Fee exceeds maximum");
        hostVoucherFeeMonths = _fee;
        emit HostVoucherFeeTierUpdated(2, _fee, msg.sender);
    }

    function setTreasuryAddress(
        address _newTreasuryAddress
    ) external onlyOwner notInEmergencyMode {
        require(_newTreasuryAddress != address(0), "Invalid treasury address");
        require(_newTreasuryAddress != treasuryAddress, "Treasury unchanged");

        address oldTreasury = treasuryAddress;
        treasuryAddress = _newTreasuryAddress;

        // Record treasury change
        treasuryHistory.push(
            TreasuryChange({
                oldTreasury: oldTreasury,
                newTreasury: _newTreasuryAddress,
                timestamp: block.timestamp,
                changedBy: msg.sender
            })
        );

        emit TreasuryUpdated(oldTreasury, _newTreasuryAddress, msg.sender);
    }

    function setPaymentAddress(
        address _newPaymentAddress
    ) external onlyOwner notInEmergencyMode {
        require(_newPaymentAddress != address(0), "Invalid payment address");
        require(
            _newPaymentAddress != paymentAddress,
            "Payment address unchanged"
        );

        address oldPaymentAddress = paymentAddress;
        paymentAddress = _newPaymentAddress;
        emit PaymentAddressUpdated(
            oldPaymentAddress,
            _newPaymentAddress,
            msg.sender
        );
    }

    function pause() external onlyOwner {
        _pause();
        emit AdminPaused(msg.sender);
    }

    function unpause() external onlyOwner {
        _unpause();
        emit AdminUnpaused(msg.sender);
    }

    /// @notice Toggle emergency mode (stops most operations)
    /// @dev Has a cooldown to prevent rapid toggling
    function toggleEmergencyMode() external onlyEmergencyOperator {
        // Check cooldown - either global or per-operator
        uint256 lastToggle = lastEmergencyToggleBy[msg.sender];
        if (lastToggle == 0) {
            lastToggle = lastEmergencyToggleTime; // Fallback to global for backwards compatibility
        }
        require(
            block.timestamp >= lastToggle + EMERGENCY_COOLDOWN,
            "Emergency toggle on cooldown"
        );

        emergencyMode = !emergencyMode;
        lastEmergencyToggleTime = block.timestamp;
        lastEmergencyToggleBy[msg.sender] = block.timestamp;
        emit EmergencyModeToggled(emergencyMode, msg.sender);
    }

    /// @notice Add or remove emergency operators
    function setEmergencyOperator(
        address operator,
        bool status
    ) external onlyOwner {
        require(operator != address(0), "Invalid operator address");
        emergencyOperators[operator] = status;
        emit EmergencyOperatorUpdated(operator, status, msg.sender);
    }

    /// @notice Emergency function to deactivate a network
    function emergencyDeactivateNetwork(
        uint256 networkId
    ) external onlyEmergencyOperator {
        require(
            address(storageContract) != address(0),
            "Storage not initialized"
        );
        storageContract.emergencyDeactivateNetwork(networkId);
    }

    /// @notice Emergency function to set platform fee (bypasses normal restrictions)
    function emergencySetPlatformFee(
        uint256 _newFeePercent
    ) external onlyEmergencyOperator {
        require(_newFeePercent <= MAX_PLATFORM_FEE, "Fee exceeds maximum");
        uint256 oldFee = platformFeePercent;
        platformFeePercent = _newFeePercent;
        feeHistory.push(
            FeeChange({
                oldFee: oldFee,
                newFee: _newFeePercent,
                timestamp: block.timestamp,
                changedBy: msg.sender
            })
        );
        emit PlatformFeeUpdated(oldFee, _newFeePercent, msg.sender);
    }

    /// @notice Emergency function to set hosting fee (bypasses normal restrictions)
    function emergencySetHostingFee(
        uint256 _newFee
    ) external onlyEmergencyOperator {
        require(_newFee <= MAX_HOSTING_FEE, "Fee exceeds maximum");
        uint256 oldFee = hostingFee;
        hostingFee = _newFee;
        hostingFeeHistory.push(
            HostingFeeChange({
                oldFee: oldFee,
                newFee: _newFee,
                timestamp: block.timestamp,
                changedBy: msg.sender
            })
        );
        emit HostingFeeUpdated(oldFee, _newFee, msg.sender);
    }

    // --- View Functions ---

    /// @notice Expose admin address for other contracts (interface compatibility)
    function admin() external view returns (address) {
        return owner();
    }

    /// @notice Get fee change history
    function getFeeHistory() external view returns (FeeChange[] memory) {
        return feeHistory;
    }

    /// @notice Get treasury change history
    function getTreasuryHistory()
        external
        view
        returns (TreasuryChange[] memory)
    {
        return treasuryHistory;
    }

    /// @notice Get hosting fee change history
    function getHostingFeeHistory()
        external
        view
        returns (HostingFeeChange[] memory)
    {
        return hostingFeeHistory;
    }

    /// @notice Get current fee in basis points (for more precise calculations)
    function getPlatformFeeBasisPoints() external view returns (uint256) {
        return platformFeePercent * 100; // Convert percentage to basis points
    }

    /// @notice Calculate platform fee for a given amount
    function calculatePlatformFee(
        uint256 amount
    ) external view returns (uint256) {
        return (amount * platformFeePercent) / 100;
    }

    /// @notice Get comprehensive admin statistics
    function getAdminStats()
        external
        view
        returns (
            uint256 totalFeeChanges,
            uint256 totalTreasuryChanges,
            uint256 totalHostingFeeChanges,
            bool isEmergencyMode,
            uint256 currentPlatformFee,
            uint256 currentHostingFee,
            address currentTreasury
        )
    {
        totalFeeChanges = feeHistory.length;
        totalTreasuryChanges = treasuryHistory.length;
        totalHostingFeeChanges = hostingFeeHistory.length;
        isEmergencyMode = emergencyMode;
        currentPlatformFee = platformFeePercent;
        currentHostingFee = hostingFee;
        currentTreasury = treasuryAddress;
    }

    /// @notice Check if address is emergency operator
    function isEmergencyOperator(
        address operator
    ) external view returns (bool) {
        return emergencyOperators[operator];
    }

    /// @notice Get latest fee change details
    function getLatestFeeChange() external view returns (FeeChange memory) {
        require(feeHistory.length > 0, "No fee changes recorded");
        return feeHistory[feeHistory.length - 1];
    }

    /// @notice Get latest treasury change details
    function getLatestTreasuryChange()
        external
        view
        returns (TreasuryChange memory)
    {
        require(treasuryHistory.length > 0, "No treasury changes recorded");
        return treasuryHistory[treasuryHistory.length - 1];
    }

    /// @notice Get latest hosting fee change details
    function getLatestHostingFeeChange()
        external
        view
        returns (HostingFeeChange memory)
    {
        require(
            hostingFeeHistory.length > 0,
            "No hosting fee changes recorded"
        );
        return hostingFeeHistory[hostingFeeHistory.length - 1];
    }

    /// @notice Get all current fees and treasury in one call (gas efficient). Matches IZaaNetAdmin interface.
    function getCurrentFees()
        external
        view
        returns (
            uint256 platformFeePercentage,
            uint256 hostingFeeAmount,
            address currentTreasury
        )
    {
        return (platformFeePercent, hostingFee, treasuryAddress);
    }

    /// @notice Get host voucher registration fee for a tier (0 = hours, 1 = days, 2 = months). USDT 6 decimals.
    function getHostVoucherFeeTier(uint8 tier) external view returns (uint256) {
        if (tier == 0) return hostVoucherFeeHours;
        if (tier == 1) return hostVoucherFeeDays;
        if (tier == 2) return hostVoucherFeeMonths;
        revert("Invalid tier");
    }

    // --- Compatibility Functions (for interface alignment) ---

    /// @notice Alternative name for treasury address (interface compatibility)
    function treasury() external view returns (address) {
        return treasuryAddress;
    }

    /// @notice Alternative name for payment address (interface compatibility)
    function payment() external view returns (address) {
        return paymentAddress;
    }

    /// @notice Check if contract is paused (interface compatibility)
    function paused() public view override(PausableUpgradeable) returns (bool) {
        return super.paused();
    }

    // Storage gap for future upgrades
    uint256[50] private __gap;
}

contracts/ZaaNetNetworkV1.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

import "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/utils/PausableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "./utils/ReentrancyGuardUpgradeable.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "./ZaaNetStorageV1.sol";
import "./interface/IZaaNetAdmin.sol";

/**
 * @title ZaaNetNetworkV1
 * @dev Upgradeable network contract for ZaaNet platform - Version 1
 * @notice Handles network registration, updates, and host management
 */
contract ZaaNetNetworkV1 is
    OwnableUpgradeable,
    PausableUpgradeable,
    UUPSUpgradeable,
    ReentrancyGuardUpgradeable
{
    using SafeERC20 for IERC20;

    ZaaNetStorageV1 public storageContract;
    IZaaNetAdmin public adminContract;
    IERC20 public usdt;

    // Constants for validation (updated for 6-decimal USDT)
    uint256 public constant MAX_PRICE_PER_SESSION = 50000000; // 50 USDT (6 decimals)
    uint256 public constant MIN_PRICE_PER_SESSION = 100; // 0.0001 USDT minimum to prevent abuse
    uint256 public constant MAX_MONGO_DATA_LENGTH = 200; // Reasonable limit for data ID

    // Gas limit protections
    uint256 public constant MAX_NETWORKS_PER_HOST = 100; // Maximum networks a single host can have
    uint256 public constant MAX_BATCH_SIZE = 50; // Maximum batch operations

    mapping(address => bool) public isHost;
    mapping(address => uint256[]) private hostNetworks;
    mapping(uint256 => address) public networkToHost; // For quick lookups

    // Rate limiting
    mapping(address => uint256) public lastRegistrationTime;
    uint256 public constant REGISTRATION_COOLDOWN = 1 minutes;

    // Enhanced events
    event NetworkRegistered(
        uint256 indexed networkId,
        address indexed hostAddress,
        string mongoDataId,
        uint256 pricePerSession,
        bool isActive,
        uint256 hostingFeePaid,
        uint256 timestamp
    );

    event HostingFeePaid(
        address indexed host,
        uint256 amount,
        uint256 timestamp
    );

    event NetworkUpdated(
        uint256 indexed networkId,
        address indexed hostAddress,
        uint256 pricePerSession,
        string mongoDataId,
        bool isActive
    );

    event NetworkPriceUpdated(
        uint256 indexed networkId,
        uint256 oldPrice,
        uint256 newPrice
    );

    event NetworkStatusChanged(
        uint256 indexed networkId,
        bool oldStatus,
        bool newStatus
    );

    event HostAdded(address indexed host);

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {}

    /// @dev Required by UUPSUpgradeable
    function _authorizeUpgrade(address) internal override onlyOwner {}

    function initialize(
        address _storageContract,
        address _adminContract,
        address _usdt
    ) public initializer {
        __Ownable_init(msg.sender);
        __Pausable_init();
        __ReentrancyGuard_init();

        require(
            _storageContract != address(0),
            "Invalid storage contract address"
        );
        require(_adminContract != address(0), "Invalid admin contract address");
        require(_usdt != address(0), "Invalid USDT contract address");

        storageContract = ZaaNetStorageV1(_storageContract);
        adminContract = IZaaNetAdmin(_adminContract);
        usdt = IERC20(_usdt);
    }

    /// @notice Register a new network with mongoDataID and pay hosting fee
    function registerNetwork(
        uint256 _pricePerSession,
        string memory _mongoDataId,
        bool _isActive
    ) external whenNotPaused nonReentrant {
        require(!adminContract.emergencyMode(), "Emergency mode active");
        require(
            block.timestamp >=
                lastRegistrationTime[msg.sender] + REGISTRATION_COOLDOWN,
            "Registration cooldown active"
        );
        require(
            _pricePerSession >= MIN_PRICE_PER_SESSION &&
                _pricePerSession <= MAX_PRICE_PER_SESSION,
            "Price out of allowed range"
        );
        require(
            bytes(_mongoDataId).length > 0 &&
                bytes(_mongoDataId).length <= MAX_MONGO_DATA_LENGTH,
            "Invalid MongoDataID length"
        );

        // Check host network limit to prevent gas exhaustion attacks
        require(
            !storageContract.hasReachedNetworkLimit(msg.sender),
            "Host has reached maximum network limit"
        );

        // Get hosting fee from admin contract
        uint256 hostingFee = adminContract.hostingFee();

        // Request a new ID from storage FIRST (before any payments)
        uint256 networkId = storageContract.incrementNetworkId();

        // Save the network details into storage
        storageContract.setNetwork(
            networkId,
            ZaaNetStorageV1.Network({
                id: networkId,
                hostAddress: msg.sender,
                pricePerSession: _pricePerSession,
                mongoDataId: _mongoDataId,
                isActive: _isActive,
                createdAt: block.timestamp,
                updatedAt: block.timestamp
            })
        );

        hostNetworks[msg.sender].push(networkId);
        networkToHost[networkId] = msg.sender;
        lastRegistrationTime[msg.sender] = block.timestamp;

        if (!isHost[msg.sender]) {
            isHost[msg.sender] = true;
            emit HostAdded(msg.sender);
        }

        // Collect hosting fee AFTER successful network registration
        if (hostingFee > 0) {
            address treasuryAddress = adminContract.treasuryAddress();
            require(treasuryAddress != address(0), "Treasury not configured");

            require(
                usdt.balanceOf(msg.sender) >= hostingFee,
                "Insufficient USDT balance for hosting fee"
            );
            require(
                usdt.allowance(msg.sender, address(this)) >= hostingFee,
                "Hosting fee not approved"
            );

            // Transfer hosting fee to treasury
            usdt.safeTransferFrom(msg.sender, treasuryAddress, hostingFee);

            // Increase ZaaNet total hosting fee earnings in storage
            storageContract.updateTotalHostingFeeAmount(hostingFee);

            emit HostingFeePaid(msg.sender, hostingFee, block.timestamp);
        }

        emit NetworkRegistered(
            networkId,
            msg.sender,
            _mongoDataId,
            _pricePerSession,
            _isActive,
            hostingFee,
            block.timestamp
        );
    }

    /// @notice Internal function to update network details
    function _updateNetwork(
        uint256 _networkId,
        uint256 _pricePerSession,
        bool _isActive,
        address sender
    ) internal {
        ZaaNetStorageV1.Network memory network = storageContract.getNetwork(
            _networkId
        );
        require(network.hostAddress == sender, "Only host can update");
        require(
            _pricePerSession >= 0 &&
                _pricePerSession >= MIN_PRICE_PER_SESSION &&
                _pricePerSession <= MAX_PRICE_PER_SESSION,
            "Price out of allowed range"
        );

        uint256 oldPrice = network.pricePerSession;
        bool oldStatus = network.isActive;

        storageContract.setNetwork(
            _networkId,
            ZaaNetStorageV1.Network({
                id: _networkId,
                hostAddress: sender,
                pricePerSession: _pricePerSession,
                mongoDataId: network.mongoDataId,
                isActive: _isActive,
                createdAt: network.createdAt,
                updatedAt: block.timestamp
            })
        );

        if (oldPrice != _pricePerSession) {
            emit NetworkPriceUpdated(_networkId, oldPrice, _pricePerSession);
        }
        if (oldStatus != _isActive) {
            emit NetworkStatusChanged(_networkId, oldStatus, _isActive);
        }

        emit NetworkUpdated(
            _networkId,
            sender,
            _pricePerSession,
            network.mongoDataId,
            _isActive
        );
    }

    /// @notice Update existing network with new details
    function updateNetwork(
        uint256 _networkId,
        uint256 _pricePerSession,
        bool _isActive
    ) external whenNotPaused nonReentrant {
        require(!adminContract.emergencyMode(), "Emergency mode active");
        _updateNetwork(_networkId, _pricePerSession, _isActive, msg.sender);
    }

    /// @notice Deactivate a network (soft delete)
    function deactivateNetwork(
        uint256 _networkId
    ) external whenNotPaused nonReentrant {
        require(!adminContract.emergencyMode(), "Emergency mode active");
        ZaaNetStorageV1.Network memory network = storageContract.getNetwork(
            _networkId
        );
        require(network.hostAddress == msg.sender, "Only host can deactivate");
        require(network.isActive, "Network already inactive");

        _updateNetwork(_networkId, network.pricePerSession, false, msg.sender);
    }

    /// @notice Get full network details from storage
    function getHostedNetworkById(
        uint256 _networkId
    ) external view returns (ZaaNetStorageV1.Network memory) {
        return storageContract.getNetwork(_networkId);
    }

    /// @notice Get all network IDs registered by a host
    function getHostNetworks(
        address hostAddress
    ) external view returns (uint256[] memory) {
        return hostNetworks[hostAddress];
    }

    /// @notice Get active networks for a host with pagination
    /// @param hostAddress The host's address
    /// @param offset Starting index for pagination
    /// @param limit Maximum number of networks to return
    function getActiveHostNetworks(
        address hostAddress,
        uint256 offset,
        uint256 limit
    ) external view returns (ZaaNetStorageV1.Network[] memory) {
        uint256[] memory networkIds = hostNetworks[hostAddress];

        // Apply gas limit protection
        if (limit > MAX_BATCH_SIZE) {
            limit = MAX_BATCH_SIZE;
        }

        // First pass: count active networks within range
        uint256 activeCount = 0;
        uint256 endIndex = offset + limit;
        if (endIndex > networkIds.length) {
            endIndex = networkIds.length;
        }

        for (uint256 i = offset; i < endIndex; i++) {
            ZaaNetStorageV1.Network memory network = storageContract.getNetwork(
                networkIds[i]
            );
            if (network.isActive) {
                activeCount++;
            }
        }

        // Second pass: collect active networks
        ZaaNetStorageV1.Network[]
            memory activeNetworks = new ZaaNetStorageV1.Network[](activeCount);
        uint256 index = 0;
        for (uint256 i = offset; i < endIndex; i++) {
            ZaaNetStorageV1.Network memory network = storageContract.getNetwork(
                networkIds[i]
            );
            if (network.isActive) {
                activeNetworks[index] = network;
                index++;
            }
        }

        return activeNetworks;
    }

    /// @notice Get total active network count for a host (gas efficient)
    function getActiveHostNetworkCount(
        address hostAddress
    ) external view returns (uint256 count) {
        uint256[] memory networkIds = hostNetworks[hostAddress];
        for (uint256 i = 0; i < networkIds.length; i++) {
            ZaaNetStorageV1.Network memory network = storageContract.getNetwork(
                networkIds[i]
            );
            if (network.isActive) {
                count++;
            }
        }
    }

    /// @notice Public method to check if an address is a registered host
    function isRegisteredHost(
        address hostAddress
    ) external view returns (bool) {
        return isHost[hostAddress];
    }

    /// @notice Get host statistics
    function getHostStats(
        address hostAddress
    )
        external
        view
        returns (
            uint256 totalNetworks,
            uint256 activeNetworks,
            uint256 totalEarnings
        )
    {
        totalNetworks = hostNetworks[hostAddress].length;
        totalEarnings = storageContract.getHostEarnings(hostAddress);

        uint256[] memory networkIds = hostNetworks[hostAddress];
        for (uint256 i = 0; i < networkIds.length; i++) {
            ZaaNetStorageV1.Network memory network = storageContract.getNetwork(
                networkIds[i]
            );
            if (network.isActive) {
                activeNetworks++;
            }
        }
    }

    /// @notice Retrieve networks with pagination (gas-optimized)
    function getNetworksPaginated(
        uint256 offset,
        uint256 limit
    )
        external
        view
        returns (ZaaNetStorageV1.Network[] memory networks, uint256 totalCount)
    {
        return storageContract.getNetworksPaginated(offset, limit);
    }

    /// @notice Get all active networks (limited to prevent gas issues)
    function getAllActiveNetworks()
        external
        view
        returns (ZaaNetStorageV1.Network[] memory)
    {
        (ZaaNetStorageV1.Network[] memory allNetworks, ) = storageContract
            .getNetworksPaginated(0, 100);
        uint256 activeCount = 0;

        for (uint256 i = 0; i < allNetworks.length; i++) {
            if (allNetworks[i].isActive) {
                activeCount++;
            }
        }

        ZaaNetStorageV1.Network[]
            memory activeNetworks = new ZaaNetStorageV1.Network[](activeCount);
        uint256 index = 0;
        for (uint256 i = 0; i < allNetworks.length; i++) {
            if (allNetworks[i].isActive) {
                activeNetworks[index] = allNetworks[i];
                index++;
            }
        }

        return activeNetworks;
    }

    /// @notice Get current hosting fee
    function getCurrentHostingFee() external view returns (uint256) {
        return adminContract.hostingFee();
    }

    /// @notice Get treasury address
    function getTreasuryAddress() external view returns (address) {
        return adminContract.treasuryAddress();
    }

    // --- Admin Functions ---

    /// @notice Update admin contract address (owner only)
    function setAdminContract(address _newAdminContract) external onlyOwner {
        require(_newAdminContract != address(0), "Invalid admin contract");
        adminContract = IZaaNetAdmin(_newAdminContract);
    }

    /// @notice Update USDT contract address (owner only)
    function setUsdtContract(address _newUsdt) external onlyOwner {
        require(_newUsdt != address(0), "Invalid USDT contract");
        usdt = IERC20(_newUsdt);
    }

    /// @notice Emergency pause (only owner)
    function pause() external onlyOwner {
        _pause();
    }

    /// @notice Unpause (only owner)
    function unpause() external onlyOwner {
        _unpause();
    }

    /// @notice Get contract statistics
    function getContractStats() external view returns (uint256 totalNetworks) {
        totalNetworks = storageContract.networkIdCounter();
    }

    // Storage gap for future upgrades
    uint256[50] private __gap;
}

contracts/ZaaNetPaymentV1.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/utils/PausableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "./utils/ReentrancyGuardUpgradeable.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/IERC20Metadata.sol";
import "./interface/IZaaNetStorage.sol";
import "./interface/IZaaNetAdmin.sol";

/**
 * @title ZaaNetPaymentV1
 * @dev Upgradeable payment contract for ZaaNet platform - Version 1
 * @notice Handles all payment processing, batch payments, and voucher registrations
 */
contract ZaaNetPaymentV1 is
    OwnableUpgradeable,
    PausableUpgradeable,
    UUPSUpgradeable,
    ReentrancyGuardUpgradeable
{
    using SafeERC20 for IERC20;

    struct BatchPayment {
        uint256 contractId;
        uint256 grossAmount;
        bytes32 voucherId;
    }

    IERC20 public usdt;
    uint8 public tokenDecimals;

    IZaaNetStorage public storageContract;
    IZaaNetAdmin public adminContract;

    // Daily withdrawal limits
    uint256 public dailyWithdrawalLimit;
    mapping(uint256 => uint256) public dailyWithdrawals; // day => amount withdrawn

    // Token whitelist for approved payment tokens
    mapping(address => bool) public whitelistedTokens;
    address[] public whitelistedTokenList;

    // Payment validation
    mapping(bytes32 => bool) public processedVouchers; // Prevent double processing

    // Events
    event TokenWhitelistUpdated(
        address indexed token,
        bool status,
        uint256 timestamp
    );
    event DailyLimitUpdated(
        uint256 newLimit,
        address updatedBy,
        uint256 timestamp
    );
    event PaymentProcessed(
        bytes32 indexed voucherId,
        uint256 indexed contractId,
        address indexed host,
        address payer,
        uint256 grossAmount,
        uint256 platformFee,
        uint256 hostAmount,
        uint256 timestamp
    );

    event DailyLimitExceeded(
        address indexed treasury,
        uint256 attemptedAmount,
        uint256 dailyLimit,
        uint256 alreadyWithdrawn
    );

    event BatchPaymentProcessed(
        uint256 batchSize,
        uint256 totalAmount,
        uint256 totalPlatformFee
    );

    /// @notice Emitted when a host registers a batch of vouchers and pays the registration fee to the treasury.
    event HostVouchersRegistered(
        address indexed host,
        uint8 indexed tier,
        uint256 voucherCount,
        uint256 totalFee,
        uint256 timestamp
    );

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {}

    /// @dev Required by UUPSUpgradeable
    function _authorizeUpgrade(address) internal override onlyOwner {}

    function initialize(
        address _usdt,
        address _storageContract,
        address _adminContract
    ) public initializer {
        __Ownable_init(msg.sender);
        __Pausable_init();
        __ReentrancyGuard_init();

        // Initialize state variables
        dailyWithdrawalLimit = 10000 * (10 ** 6); // 10K USDT

        require(_usdt != address(0), "token zero");
        require(_storageContract != address(0), "storage zero");
        require(_adminContract != address(0), "admin zero");

        usdt = IERC20(_usdt);
        tokenDecimals = IERC20Metadata(_usdt).decimals();
        require(tokenDecimals == 6, "Token decimals must be 6");

        // Add the initial token to whitelist (must be a legitimate token)
        whitelistedTokens[_usdt] = true;
        whitelistedTokenList.push(_usdt);
        emit TokenWhitelistUpdated(_usdt, true, block.timestamp);

        storageContract = IZaaNetStorage(_storageContract);
        adminContract = IZaaNetAdmin(_adminContract);
    }

    // Modifiers
    modifier onlyTreasuryOrOwner() {
        address treasury = adminContract.treasuryAddress();
        require(
            msg.sender == owner() ||
                (treasury != address(0) && msg.sender == treasury),
            "Not authorized"
        );
        _;
    }

    /**
     * @notice Process a payment for a voucher with enhanced security controls
     * @param _contractId The ID of the network contract
     * @param _grossAmount The total amount paid by the user (in USDT, 6 decimals)
     * @param _voucherId Unique voucher ID to prevent double processing
     * @dev Enforces max individual payment, daily limits, and prevents double processing. Daily limit is consumed only on success.
     */
    function processPayment(
        uint256 _contractId,
        uint256 _grossAmount,
        bytes32 _voucherId
    ) external whenNotPaused nonReentrant {
        require(
            msg.sender == adminContract.paymentAddress(),
            "Not payment address"
        );
        require(!adminContract.emergencyMode(), "Emergency mode active");
        require(!processedVouchers[_voucherId], "Voucher already processed");
        require(_grossAmount > 0, "Invalid amount");

        IZaaNetStorage.Network memory network = storageContract.getNetwork(
            _contractId
        );
        require(network.isActive, "Network not active");

        uint256 feePercent = adminContract.platformFeePercent();

        address treasuryWallet = adminContract.treasuryAddress();
        require(treasuryWallet != address(0), "Invalid treasury");

        // Check daily limit (will be consumed after successful payment in _executePayment)
        uint256 today = block.timestamp / 1 days;
        uint256 currentUsage = dailyWithdrawals[today];
        uint256 remaining = currentUsage >= dailyWithdrawalLimit
            ? 0
            : dailyWithdrawalLimit - currentUsage;
        require(_grossAmount <= remaining, "Exceeds daily limit");

        _executePayment(
            _contractId,
            _grossAmount,
            _voucherId,
            network,
            feePercent,
            treasuryWallet,
            today,
            _grossAmount
        );
    }

    /**
     * @notice Process a batch of payments for vouchers with enhanced security controls
     * @dev Limits: max 50 payments per batch, total batch amount must not exceed daily limit
     * @param payments Array of BatchPayment structs
     */
    function processBatchPayments(
        BatchPayment[] calldata payments
    ) external whenNotPaused nonReentrant {
        require(
            msg.sender == adminContract.paymentAddress(),
            "Not payment address"
        );
        require(!adminContract.emergencyMode(), "Emergency mode active");
        require(
            payments.length > 0 && payments.length <= 50,
            "Invalid batch size"
        );

        uint256 totalAmount = 0;
        uint256 feePercent = adminContract.platformFeePercent();

        address treasuryWallet = adminContract.treasuryAddress();
        require(treasuryWallet != address(0), "Invalid treasury");

        // First pass: validate all payments and calculate total (no state changes yet)
        bytes32[] memory seenVouchers = new bytes32[](payments.length);
        uint256 seenCount = 0;

        for (uint256 i = 0; i < payments.length; i++) {
            BatchPayment memory payment = payments[i];

            for (uint256 j = 0; j < seenCount; j++) {
                require(
                    seenVouchers[j] != payment.voucherId,
                    "Duplicate voucher in batch"
                );
            }
            seenVouchers[seenCount] = payment.voucherId;
            seenCount++;

            require(payment.grossAmount > 0, "Invalid amount");
            require(
                !processedVouchers[payment.voucherId],
                "Voucher already processed"
            );

            IZaaNetStorage.Network memory network = storageContract.getNetwork(
                payment.contractId
            );
            require(network.isActive, "Network not active");

            totalAmount += payment.grossAmount;
        }

        // Check and consume daily limit atomically
        uint256 today = block.timestamp / 1 days;
        uint256 currentUsage = dailyWithdrawals[today];
        uint256 remaining = currentUsage >= dailyWithdrawalLimit
            ? 0
            : dailyWithdrawalLimit - currentUsage;
        require(totalAmount <= remaining, "Exceeds daily limit");
        dailyWithdrawals[today] = currentUsage + totalAmount;

        require(
            usdt.balanceOf(address(this)) >= totalAmount,
            "Insufficient contract balance"
        );

        // Second pass: execute all payments
        uint256 totalPlatformFee = 0;

        for (uint256 i = 0; i < payments.length; i++) {
            BatchPayment memory payment = payments[i];

            IZaaNetStorage.Network memory network = storageContract.getNetwork(
                payment.contractId
            );

            uint256 platformFee = (payment.grossAmount * feePercent) / 100;
            uint256 hostAmount = payment.grossAmount - platformFee;

            uint256 paymentTotal = hostAmount + platformFee;
            require(
                usdt.balanceOf(address(this)) >= paymentTotal,
                "Insufficient balance for payment"
            );

            usdt.safeTransfer(network.hostAddress, hostAmount);

            storageContract.increaseHostEarnings(
                network.hostAddress,
                hostAmount
            );

            totalPlatformFee += platformFee;

            processedVouchers[payment.voucherId] = true;

            emit PaymentProcessed(
                payment.voucherId,
                payment.contractId,
                network.hostAddress,
                msg.sender,
                payment.grossAmount,
                platformFee,
                hostAmount,
                block.timestamp
            );
        }

        if (totalPlatformFee > 0) {
            usdt.safeTransfer(treasuryWallet, totalPlatformFee);
            storageContract.increaseClientVoucherFeeEarnings(totalPlatformFee);
        }

        storageContract.updateTotalSessionPaymentsAmount(totalAmount);

        emit BatchPaymentProcessed(
            payments.length,
            totalAmount,
            totalPlatformFee
        );
    }

    /**
     * @notice Register host-created vouchers on-chain and pay the platform registration fee in USDT.
     * @dev The host must first approve this contract to spend the required USDT amount.
     *      totalFee = getHostVoucherFeeTier(tier) * voucherIds.length, USDT 6 decimals.
     * @param voucherIds Array of voucher identifiers (off-chain IDs, e.g. bytes32 codes)
     * @param tier Fee tier: 0 = hours (≤24h), 1 = days (≤30d), 2 = months (>30d)
     */
    function registerHostVouchersAndPayFee(
        bytes32[] calldata voucherIds,
        uint8 tier
    ) external whenNotPaused nonReentrant {
        require(voucherIds.length > 0, "No vouchers");
        require(voucherIds.length <= 1000, "Too many vouchers");
        require(tier <= 2, "Invalid tier");

        uint256 feePerVoucher = adminContract.getHostVoucherFeeTier(tier);
        require(feePerVoucher > 0, "Host voucher fee not set");

        uint256 count = voucherIds.length;
        uint256 totalFee = feePerVoucher * count;
        require(totalFee > 0, "Total fee is zero");

        address treasuryWallet = adminContract.treasuryAddress();
        require(treasuryWallet != address(0), "Invalid treasury");

        usdt.safeTransferFrom(msg.sender, treasuryWallet, totalFee);

        storageContract.increaseHostVoucherFeeEarnings(totalFee);

        emit HostVouchersRegistered(
            msg.sender,
            tier,
            count,
            totalFee,
            block.timestamp
        );
    }

    /**
     * @notice Internal function to execute payment
     */
    function _executePayment(
        uint256 _contractId,
        uint256 _grossAmount,
        bytes32 _voucherId,
        IZaaNetStorage.Network memory network,
        uint256 feePercent,
        address treasuryWallet,
        uint256 _today,
        uint256 _amount
    ) internal {
        processedVouchers[_voucherId] = true;

        uint256 platformFee = (_grossAmount * feePercent) / 100;
        uint256 hostAmount = _grossAmount - platformFee;

        require(
            usdt.balanceOf(address(this)) >= hostAmount + platformFee,
            "Insufficient contract balance for payment"
        );

        usdt.safeTransfer(network.hostAddress, hostAmount);

        if (platformFee > 0) {
            usdt.safeTransfer(treasuryWallet, platformFee);
        }

        storageContract.increaseHostEarnings(network.hostAddress, hostAmount);
        if (platformFee > 0) {
            storageContract.increaseClientVoucherFeeEarnings(platformFee);
        }

        storageContract.updateTotalSessionPaymentsAmount(_grossAmount);

        // Consume daily limit only after successful payment
        dailyWithdrawals[_today] += _amount;

        emit PaymentProcessed(
            _voucherId,
            _contractId,
            network.hostAddress,
            msg.sender,
            _grossAmount,
            platformFee,
            hostAmount,
            block.timestamp
        );
    }

    /**
     * @notice Set daily withdrawal limit (owner only)
     */
    function setDailyWithdrawalLimit(uint256 _newLimit) external onlyOwner {
        require(_newLimit > 0, "Invalid limit");
        // Add reasonable upper bound to prevent accidentally setting too high
        require(_newLimit <= 1000000 * (10 ** 6), "Limit exceeds maximum");
        dailyWithdrawalLimit = _newLimit;
        emit DailyLimitUpdated(_newLimit, msg.sender, block.timestamp);
    }

    /**
     * @notice Add a token to the whitelist (owner only)
     * @dev Prevents malicious tokens from being used as payment
     */
    function addTokenToWhitelist(address _token) external onlyOwner {
        require(_token != address(0), "Invalid token address");
        require(!whitelistedTokens[_token], "Token already whitelisted");

        // Validate token has correct decimals
        uint8 decimals = IERC20Metadata(_token).decimals();
        require(decimals == 6, "Token must have 6 decimals");

        // Try to verify it's a valid token by checking basic interface
        try IERC20(_token).totalSupply() returns (uint256) {
            // Basic check passed - add to whitelist
        } catch {
            revert("Invalid token contract");
        }

        whitelistedTokens[_token] = true;
        whitelistedTokenList.push(_token);
        emit TokenWhitelistUpdated(_token, true, block.timestamp);
    }

    /**
     * @notice Remove a token from the whitelist (owner only)
     */
    function removeTokenFromWhitelist(address _token) external onlyOwner {
        require(whitelistedTokens[_token], "Token not whitelisted");
        require(_token != address(usdt), "Cannot remove primary payment token");

        whitelistedTokens[_token] = false;
        emit TokenWhitelistUpdated(_token, false, block.timestamp);
    }

    /**
     * @notice Check if a token is whitelisted
     */
    function isTokenWhitelisted(address _token) external view returns (bool) {
        return whitelistedTokens[_token];
    }

    /**
     * @notice Get the list of whitelisted tokens
     */
    function getWhitelistedTokens() external view returns (address[] memory) {
        return whitelistedTokenList;
    }

    /**
     * @notice Get today's withdrawal amount
     */
    function getTodayWithdrawals() external view returns (uint256) {
        uint256 today = block.timestamp / 1 days;
        return dailyWithdrawals[today];
    }

    /**
     * @notice Check if voucher has been processed
     */
    function isVoucherProcessed(
        bytes32 _voucherId
    ) external view returns (bool) {
        return processedVouchers[_voucherId];
    }

    /**
     * @notice Get remaining daily limit
     */
    function getRemainingDailyLimit() public view returns (uint256) {
        uint256 today = block.timestamp / 1 days;
        uint256 used = dailyWithdrawals[today];
        return used >= dailyWithdrawalLimit ? 0 : dailyWithdrawalLimit - used;
    }

    /**
     * @notice Withdraw USDT to recipient (owner only). Counts toward daily limit.
     */
    function withdrawToken(address _to, uint256 _amount) external onlyOwner {
        require(_to != address(0), "Invalid recipient address");
        require(_amount > 0, "Amount must be greater than zero");
        require(
            usdt.balanceOf(address(this)) >= _amount,
            "Insufficient contract balance"
        );

        uint256 today = block.timestamp / 1 days;
        uint256 currentUsage = dailyWithdrawals[today];
        uint256 remaining = currentUsage >= dailyWithdrawalLimit
            ? 0
            : dailyWithdrawalLimit - currentUsage;
        require(_amount <= remaining, "Exceeds daily withdrawal limit");
        dailyWithdrawals[today] = currentUsage + _amount;

        usdt.safeTransfer(_to, _amount);
        storageContract.updateZaanetWithdrawalsAmount(_amount);
    }

    function pause() external onlyOwner {
        _pause();
    }

    function unpause() external onlyOwner {
        _unpause();
    }

    function rescueERC20(
        address _erc20,
        address _to,
        uint256 _amount
    ) external onlyOwner {
        require(_to != address(0), "zero to");
        require(_erc20 != address(usdt), "Cannot rescue payment token");
        IERC20(_erc20).safeTransfer(_to, _amount);
    }

    function contractTokenBalance() external view returns (uint256) {
        return usdt.balanceOf(address(this));
    }

    // Storage gap for future upgrades
    uint256[50] private __gap;
}

contracts/ZaaNetStorageV1.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

import "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/utils/PausableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "./utils/ReentrancyGuardUpgradeable.sol";

/**
 * @title ZaaNetStorageV1
 * @dev Upgradeable storage contract for ZaaNet platform - Version 1
 * @notice This contract stores all the data for networks, earnings, and vouchers
 */
contract ZaaNetStorageV1 is
    OwnableUpgradeable,
    PausableUpgradeable,
    UUPSUpgradeable,
    ReentrancyGuardUpgradeable
{
    struct Network {
        uint256 id;
        address hostAddress;
        uint256 pricePerSession;
        string mongoDataId;
        bool isActive;
        uint256 createdAt;
        uint256 updatedAt;
    }

    // Tracking variables
    mapping(address => bool) public allowedCallers; // Addresses allowed to call storage functions
    uint256 public networkIdCounter; // Counter for network IDs
    uint256 public totalSessionPaymentsAmount; // Total amount processed through payments
    uint256 public totalWithdrawalsAmount; // Total amount processed through withdrawals
    uint256 public totalHostingFeeAmount; // Total amount processed through network hosting fees

    // Safety limits
    uint256 public constant MAX_NETWORKS_PER_HOST = 100; // Maximum networks per host
    mapping(address => uint256) public hostNetworkCount; // Track network count per host

    // Voucher-related earnings
    uint256 public totalClientVoucherFeeAmount; // Total earnings from client voucher usage (redemptions)
    uint256 public totalHostVoucherFeeAmount; // Total earnings from host voucher registration fees

    // Mappings for data management
    mapping(uint256 => Network) public networks;
    mapping(address => uint256) public hostEarnings;
    mapping(address => uint256[]) public hostNetworkIds;
    mapping(uint256 => bool) public networkExists;

    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {}

    function initialize() public initializer {
        __Ownable_init(msg.sender);
        __Pausable_init();
        __ReentrancyGuard_init();
    }

    /// @dev Required by UUPSUpgradeable
    function _authorizeUpgrade(address) internal override onlyOwner {}

    modifier onlyAllowed() {
        require(
            allowedCallers[msg.sender] || msg.sender == owner(),
            "Not authorized"
        );
        _;
    }

    modifier whenStorageNotPaused() {
        require(!paused(), "Storage paused");
        _;
    }

    event AllowedCallerUpdated(address indexed caller, bool status);
    event NetworkStored(
        uint256 indexed id,
        address indexed hostAddress,
        uint256 pricePerSession
    );
    event NetworkUpdated(uint256 indexed id, address indexed hostAddress);
    event SessionStored(
        uint256 indexed sessionId,
        address indexed paymentAddress,
        uint256 amount
    );
    event HostEarningsUpdated(address indexed hostAddress, uint256 totalEarned);
    event ClientVoucherFeeEarningsUpdated(uint256 totalEarned);
    event HostVoucherFeeEarningsUpdated(uint256 totalEarned);

    // --- Caller Management ---
    function setAllowedCaller(address _caller, bool status) external onlyOwner {
        require(_caller != address(0), "Invalid caller address");
        allowedCallers[_caller] = status;
        emit AllowedCallerUpdated(_caller, status);
    }

    // Batch set allowed callers for initial setup
    function setAllowedCallers(
        address[] calldata _callers,
        bool status
    ) external onlyOwner {
        require(_callers.length <= 100, "Too many callers"); // Gas protection
        for (uint256 i = 0; i < _callers.length; i++) {
            require(_callers[i] != address(0), "Invalid caller address");
            require(_callers[i] != address(this), "Cannot add self");
            allowedCallers[_callers[i]] = status;
            emit AllowedCallerUpdated(_callers[i], status);
        }
    }

    /// @notice Get the count of networks for a host
    function getHostNetworkCount(
        address hostAddress
    ) external view returns (uint256) {
        return hostNetworkCount[hostAddress];
    }

    /// @notice Check if host has reached maximum network limit
    function hasReachedNetworkLimit(
        address hostAddress
    ) external view returns (bool) {
        return hostNetworkCount[hostAddress] >= MAX_NETWORKS_PER_HOST;
    }

    // --- Network Functions ---
    function incrementNetworkId()
        external
        onlyAllowed
        whenStorageNotPaused
        returns (uint256)
    {
        return ++networkIdCounter;
    }

    function setNetwork(
        uint256 id,
        Network calldata net
    ) external onlyAllowed whenStorageNotPaused nonReentrant {
        require(id > 0, "Invalid network ID");
        require(net.id == id, "Mismatched network ID");
        require(net.hostAddress != address(0), "Invalid host address");
        require(net.pricePerSession <= 50000000, "Price exceeds maximum"); // Allows zero for free sessions
        require(bytes(net.mongoDataId).length > 0, "MongoDataID required");

        bool isNewNetwork = !networkExists[id];

        if (!isNewNetwork) {
            require(
                networks[id].hostAddress == net.hostAddress,
                "Host change not allowed"
            );
        }

        networks[id] = Network({
            id: id,
            hostAddress: net.hostAddress,
            pricePerSession: net.pricePerSession,
            mongoDataId: net.mongoDataId,
            isActive: net.isActive,
            createdAt: isNewNetwork ? block.timestamp : networks[id].createdAt,
            updatedAt: block.timestamp
        });

        if (isNewNetwork) {
            networkExists[id] = true;
            hostNetworkIds[net.hostAddress].push(id);
            emit NetworkStored(id, net.hostAddress, net.pricePerSession);
        } else {
            emit NetworkUpdated(id, net.hostAddress);
        }
    }

    function getNetwork(uint256 id) external view returns (Network memory) {
        require(networkExists[id], "Network does not exist");
        return networks[id];
    }

    /// @notice Returns only networks that exist (networkExists[id]); total is networkIdCounter.
    function getNetworksPaginated(
        uint256 offset,
        uint256 limit
    ) external view returns (Network[] memory, uint256 total) {
        total = networkIdCounter;
        if (total == 0 || offset >= total) {
            return (new Network[](0), total);
        }

        uint256 end = offset + limit;
        if (end > total) {
            end = total;
        }

        // First pass: count existing networks in range [offset+1, end] (IDs start at 1)
        uint256 existingCount = 0;
        for (uint256 i = offset; i < end; i++) {
            if (networkExists[i + 1]) {
                existingCount++;
            }
        }

        Network[] memory result = new Network[](existingCount);
        uint256 idx = 0;
        for (uint256 i = offset; i < end; i++) {
            uint256 networkId = i + 1; // Networks start at ID 1
            if (networkExists[networkId]) {
                result[idx] = networks[networkId];
                idx++;
            }
        }
        return (result, total);
    }

    function getHostNetworks(
        address hostAddress
    ) external view returns (uint256[] memory) {
        return hostNetworkIds[hostAddress];
    }

    // --- Earnings ---
    function increaseHostEarnings(
        address hostAddress,
        uint256 amount
    ) external onlyAllowed whenStorageNotPaused nonReentrant {
        require(hostAddress != address(0), "Invalid host address");
        require(amount > 0, "Amount must be greater than 0");

        hostEarnings[hostAddress] += amount;
        emit HostEarningsUpdated(hostAddress, hostEarnings[hostAddress]);
    }

    function getHostEarnings(
        address hostAddress
    ) external view returns (uint256) {
        return hostEarnings[hostAddress];
    }

    /// @notice Increase total earnings from client voucher usage (voucher redemptions)
    function increaseClientVoucherFeeEarnings(
        uint256 amount
    ) external onlyAllowed whenStorageNotPaused nonReentrant {
        require(amount > 0, "Amount must be greater than 0");
        totalClientVoucherFeeAmount += amount;
        emit ClientVoucherFeeEarningsUpdated(totalClientVoucherFeeAmount);
    }

    /// @notice Increase total earnings from host voucher registration fees
    function increaseHostVoucherFeeEarnings(
        uint256 amount
    ) external onlyAllowed whenStorageNotPaused nonReentrant {
        require(amount > 0, "Amount must be greater than 0");
        totalHostVoucherFeeAmount += amount;
        emit HostVoucherFeeEarningsUpdated(totalHostVoucherFeeAmount);
    }

    function updateTotalSessionPaymentsAmount(
        uint256 amount
    ) external onlyAllowed whenStorageNotPaused nonReentrant {
        require(amount > 0, "Amount must be greater than 0");
        totalSessionPaymentsAmount += amount;
    }

    function updateZaanetWithdrawalsAmount(
        uint256 amount
    ) external onlyAllowed whenStorageNotPaused nonReentrant {
        require(amount > 0, "Amount must be greater than 0");
        totalWithdrawalsAmount += amount;
    }

    function updateTotalHostingFeeAmount(
        uint256 amount
    ) external onlyAllowed whenStorageNotPaused nonReentrant {
        require(amount > 0, "Amount must be greater than 0");
        totalHostingFeeAmount += amount;
    }

    // Emergency function to deactivate a network (callable by owner or allowed callers e.g. Admin)
    function emergencyDeactivateNetwork(
        uint256 networkId
    ) external onlyAllowed {
        require(networkExists[networkId], "Network does not exist");
        if (!networks[networkId].isActive) {
            return; // Already inactive, no need to emit again
        }
        networks[networkId].isActive = false;
        networks[networkId].updatedAt = block.timestamp;
        emit NetworkUpdated(networkId, networks[networkId].hostAddress);
    }

    function pause() external onlyOwner {
        _pause();
    }

    function unpause() external onlyOwner {
        _unpause();
    }

    // Storage gap for future upgrades
    uint256[50] private __gap;
}

